doppler:index/changeRequestPolicy:Change.description:
Manage a Doppler change request policy.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as doppler from "@nellisauction/pulumi-doppler";
import * as std from "@pulumi/std";

export = async () => {
    const nic = await doppler.getUser({
        email: "nic@doppler.com",
    });
    const emily = await doppler.getUser({
        email: "emily@doppler.com",
    });
    const testProj = new doppler.Project("test_proj", {
        name: "my-test-project",
        description: "This is a test project",
    });
    const prd = new doppler.Environment("prd", {
        project: testProj.name,
        slug: "prd",
        name: "prd",
    });
    const ci = new doppler.Environment("ci", {
        project: testProj.name,
        slug: "ci",
        name: "CI-CD",
    });
    const ciGithub = new doppler.Config("ci_github", {
        project: testProj.name,
        environment: ci.slug,
        name: "ci_github",
    });
    const prodReviewers = new doppler.Group("prod_reviewers", {name: "Prod Reviewers"});
    const prodReviewersGroupMember: doppler.GroupMember[] = [];
    for (const range of std.toset({
        input: [nic.slug],
    }).result.map((v, k) => ({key: k, value: v}))) {
        prodReviewersGroupMember.push(new doppler.GroupMember(`prod_reviewers-${range.key}`, {
            groupSlug: prodReviewers.slug,
            userSlug: range.value,
        }));
    }
    const prdReview = new doppler.ChangeRequestPolicy("prd_review", {
        name: "Prod Review",
        description: `A change request policy which requires 2 total approvals, and 1 approval from emily or any member of the prod_reviewers group.
Reviews from the author of the change request are not counted.
This policy is enforced in all configs of the prd environment of test_proj, as well as the ci_github branch config.
`,
        rules: {
            disallowSelfReview: true,
            autoAssignReviewers: "matchCount",
            requiredReviewers: [
                {
                    count: 2,
                },
                {
                    count: 1,
                    groupSlugs: [prodReviewers.slug],
                    userSlugs: [emily.slug],
                },
            ],
        },
        targets: {
            projects: [{
                projectName: testProj.name,
                environmentSlugs: [prd.slug],
                configNames: [ciGithub.name],
            }],
        },
    });
}
