public class App {
    public static void main(String[] args) {
        Pulumi.run(App::stack);
    }

    public static void stack(Context ctx) {
        final var nic = DopplerFunctions.getUser(GetUserArgs.builder()
            .email("nic@doppler.com")
            .build());

        final var emily = DopplerFunctions.getUser(GetUserArgs.builder()
            .email("emily@doppler.com")
            .build());

        var testProj = new Project("testProj", ProjectArgs.builder()
            .name("my-test-project")
            .description("This is a test project")
            .build());

        var prd = new Environment("prd", EnvironmentArgs.builder()
            .project(testProj.name())
            .slug("prd")
            .name("prd")
            .build());

        var ci = new Environment("ci", EnvironmentArgs.builder()
            .project(testProj.name())
            .slug("ci")
            .name("CI-CD")
            .build());

        var ciGithub = new Config("ciGithub", ConfigArgs.builder()
            .project(testProj.name())
            .environment(ci.slug())
            .name("ci_github")
            .build());

        var prodReviewers = new Group("prodReviewers", GroupArgs.builder()
            .name("Prod Reviewers")
            .build());

        for (var range : KeyedValue.of(com.pulumi.std.StdFunctions(TosetArgs.builder()
            .input(nic.slug())
            .build()).result())) {
            new GroupMember("prodReviewersGroupMember-" + range.key(), GroupMemberArgs.builder()
                .groupSlug(prodReviewers.slug())
                .userSlug(range.value())
                .build());
        }

        var prdReview = new ChangeRequestPolicy("prdReview", ChangeRequestPolicyArgs.builder()
            .name("Prod Review")
            .description("""
A change request policy which requires 2 total approvals, and 1 approval from emily or any member of the prod_reviewers group.
Reviews from the author of the change request are not counted.
This policy is enforced in all configs of the prd environment of test_proj, as well as the ci_github branch config.
            """)
            .rules(ChangeRequestPolicyRulesArgs.builder()
                .disallowSelfReview(true)
                .autoAssignReviewers("matchCount")
                .requiredReviewers(                
                    ChangeRequestPolicyRulesRequiredReviewerArgs.builder()
                        .count(2)
                        .build(),
                    ChangeRequestPolicyRulesRequiredReviewerArgs.builder()
                        .count(1)
                        .groupSlugs(prodReviewers.slug())
                        .userSlugs(emily.slug())
                        .build())
                .build())
            .targets(ChangeRequestPolicyTargetsArgs.builder()
                .projects(ChangeRequestPolicyTargetsProjectArgs.builder()
                    .projectName(testProj.name())
                    .environmentSlugs(prd.slug())
                    .configNames(ciGithub.name())
                    .build())
                .build())
            .build());

    }
}
