import * as std from "@pulumi/std";

const iGcpSakExtid = new doppler.IntegrationExternalId("i_gcp_sak_extid", {integrationType: "gcp_service_account_keys"});
const gcpsaDopplerImpersonate = new gcp.serviceaccount.Account("gcpsa_doppler_impersonate", {
    accountId: "xxxxxxxxxxx",
    description: std.format({
        input: "doppler_impersonate:%s",
        args: [iGcpSakExtid.id],
    }).then(invoke => invoke.result),
    displayName: "xxxxxxxxxx",
});
const dopplerRotationImpersonatePolicy = gcp.organizations.getIAMPolicyOutput({
    bindings: [
        {
            role: "roles/iam.serviceAccountViewer",
            members: [
                gcpsaDopplerImpersonate.member,
                "serviceAccount:operator@doppler-integrations.iam.gserviceaccount.com",
            ],
        },
        {
            role: "roles/iam.serviceAccountTokenCreator",
            members: ["serviceAccount:operator@doppler-integrations.iam.gserviceaccount.com"],
        },
    ],
});
const gcpPolicyImpersonate = new gcp.serviceaccount.IAMPolicy("gcp_policy_impersonate", {
    serviceAccountId: gcpsaDopplerImpersonate.name,
    policyData: dopplerRotationImpersonatePolicy.apply(dopplerRotationImpersonatePolicy => dopplerRotationImpersonatePolicy.policyData),
});
const gcpsaRotated = new gcp.serviceaccount.Account("gcpsa_rotated", {
    accountId: "xxxxxxxxxxxxxxxxxx",
    displayName: "xxxxxxxxxxxxxxxxxx",
});
const dopplerRotatedUserPolicy = gcp.organizations.getIAMPolicyOutput({
    bindings: [{
        role: "roles/iam.serviceAccountKeyAdmin",
        members: [gcpsaDopplerImpersonate.member],
    }],
});
const gcpPolicyRotated = new gcp.serviceaccount.IAMPolicy("gcp_policy_rotated", {
    serviceAccountId: gcpsaRotated.name,
    policyData: dopplerRotatedUserPolicy.apply(dopplerRotatedUserPolicy => dopplerRotatedUserPolicy.policyData),
});
const iGcpSak = new doppler.IntegrationGcpServiceAccountKeys("i_gcp_sak", {
    name: "TF GCP Service Account Keys",
    impersonatedServiceAccount: gcpsaDopplerImpersonate.email,
    externalId: iGcpSakExtid.id,
});
